const n=JSON.parse('{"key":"v-78c37848","path":"/posts/%E4%B8%AD%E9%97%B4%E4%BB%B6/mysql/%E5%9F%BA%E7%A1%80%E7%9F%A5%E8%AF%8611%E3%80%81innoDB%E5%92%8CMyISAM.html","title":"基础知识11、innoDB和MyISAM","lang":"en-US","frontmatter":{"icon":"pen-to-square","date":"2022-01-02T00:00:00.000Z","category":["mysql"],"tag":["InnoDB","MyISAM","存储引擎"],"star":true,"description":"基础知识11、innoDB和MyISAM 区别 InnoDB和MyISAM是使用MySQL时最常用的两种引擎类型，我们重点来看下两者区别。 事务和外键 InnoDB支持事务和外键，具有安全性和完整性，适合大量insert或update操作 MyISAM不支持事务和外键，它提供高速存储和检索，适合大量的select查询操作 锁机制 InnoDB支持行级锁，锁定指定记录。基于索引来加锁实现。 MyISAM支持表级锁，锁定整张表。 索引结构 InnoDB使用聚集索引（聚簇索引），索引和记录在一起存储，既缓存索引，也缓存记录。 MyISAM使用非聚集索引（非聚簇索引），索引和记录分开。 并发处理能力 MyISAM使用表锁，会导致写操作并发率低，读之间并不阻塞，读写阻塞。 InnoDB读写阻塞可以与隔离级别有关，可以采用多版本并发控制（MVCC）来支持高并发 存储文件 InnoDB表对应两个文件，一个.frm表结构文件，一个.ibd数据文件。InnoDB表最大支持64TB； MyISAM表对应三个文件，一个.frm表结构文件，一个MYD表数据文件，一个.MYI索引文件。从MySQL5.0开始默认限制是256TB。 image.png","head":[["meta",{"property":"og:url","content":"https://y-aong.github.io/orderlines_blog/orderlines_blog/posts/%E4%B8%AD%E9%97%B4%E4%BB%B6/mysql/%E5%9F%BA%E7%A1%80%E7%9F%A5%E8%AF%8611%E3%80%81innoDB%E5%92%8CMyISAM.html"}],["meta",{"property":"og:site_name","content":"ORDERLINES"}],["meta",{"property":"og:title","content":"基础知识11、innoDB和MyISAM"}],["meta",{"property":"og:description","content":"基础知识11、innoDB和MyISAM 区别 InnoDB和MyISAM是使用MySQL时最常用的两种引擎类型，我们重点来看下两者区别。 事务和外键 InnoDB支持事务和外键，具有安全性和完整性，适合大量insert或update操作 MyISAM不支持事务和外键，它提供高速存储和检索，适合大量的select查询操作 锁机制 InnoDB支持行级锁，锁定指定记录。基于索引来加锁实现。 MyISAM支持表级锁，锁定整张表。 索引结构 InnoDB使用聚集索引（聚簇索引），索引和记录在一起存储，既缓存索引，也缓存记录。 MyISAM使用非聚集索引（非聚簇索引），索引和记录分开。 并发处理能力 MyISAM使用表锁，会导致写操作并发率低，读之间并不阻塞，读写阻塞。 InnoDB读写阻塞可以与隔离级别有关，可以采用多版本并发控制（MVCC）来支持高并发 存储文件 InnoDB表对应两个文件，一个.frm表结构文件，一个.ibd数据文件。InnoDB表最大支持64TB； MyISAM表对应三个文件，一个.frm表结构文件，一个MYD表数据文件，一个.MYI索引文件。从MySQL5.0开始默认限制是256TB。 image.png"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"property":"og:updated_time","content":"2024-04-08T14:50:55.000Z"}],["meta",{"property":"article:author","content":"Y-aong"}],["meta",{"property":"article:tag","content":"InnoDB"}],["meta",{"property":"article:tag","content":"MyISAM"}],["meta",{"property":"article:tag","content":"存储引擎"}],["meta",{"property":"article:published_time","content":"2022-01-02T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2024-04-08T14:50:55.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"基础知识11、innoDB和MyISAM\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2022-01-02T00:00:00.000Z\\",\\"dateModified\\":\\"2024-04-08T14:50:55.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Y-aong\\",\\"url\\":\\"https://github.com/Y-aong\\"}]}"]]},"headers":[{"level":3,"title":"区别","slug":"区别","link":"#区别","children":[]},{"level":3,"title":"MyISAM 适用场景","slug":"myisam-适用场景","link":"#myisam-适用场景","children":[]},{"level":3,"title":"InnoDB 适用场景","slug":"innodb-适用场景","link":"#innodb-适用场景","children":[]},{"level":3,"title":"两种引擎该如何选择？","slug":"两种引擎该如何选择","link":"#两种引擎该如何选择","children":[]},{"level":3,"title":"innoDB的三大特征","slug":"innodb的三大特征","link":"#innodb的三大特征","children":[]},{"level":3,"title":"InnoDB存储引擎支持四种行格式","slug":"innodb存储引擎支持四种行格式","link":"#innodb存储引擎支持四种行格式","children":[]},{"level":3,"title":"COMPACT 行记录格式","slug":"compact-行记录格式","link":"#compact-行记录格式","children":[]}],"git":{"createdTime":1712587855000,"updatedTime":1712587855000,"contributors":[{"name":"Y-aong","email":"1627469727@qq.com","commits":1}]},"readingTime":{"minutes":10.63,"words":3189},"filePathRelative":"posts/中间件/mysql/基础知识11、innoDB和MyISAM.md","localizedDate":"January 2, 2022","excerpt":"<h1> 基础知识11、innoDB和MyISAM</h1>\\n<h3> 区别</h3>\\n<p>InnoDB和MyISAM是使用MySQL时最常用的两种引擎类型，我们重点来看下两者区别。</p>\\n<ul>\\n<li>\\n<p>事务和外键<br>\\nInnoDB支持事务和外键，具有安全性和完整性，适合大量insert或update操作<br>\\nMyISAM不支持事务和外键，它提供高速存储和检索，适合大量的select查询操作</p>\\n</li>\\n<li>\\n<p>锁机制<br>\\nInnoDB支持行级锁，锁定指定记录。基于索引来加锁实现。<br>\\nMyISAM支持表级锁，锁定整张表。</p>\\n</li>\\n<li>\\n<p>索引结构<br>\\nInnoDB使用聚集索引（聚簇索引），索引和记录在一起存储，既缓存索引，也缓存记录。<br>\\nMyISAM使用非聚集索引（非聚簇索引），索引和记录分开。</p>\\n</li>\\n<li>\\n<p>并发处理能力<br>\\nMyISAM使用表锁，会导致写操作并发率低，读之间并不阻塞，读写阻塞。<br>\\nInnoDB读写阻塞可以与隔离级别有关，可以采用多版本并发控制（MVCC）来支持高并发</p>\\n</li>\\n<li>\\n<p>存储文件<br>\\nInnoDB表对应两个文件，一个.frm表结构文件，一个.ibd数据文件。InnoDB表最大支持64TB；<br>\\nMyISAM表对应三个文件，一个.frm表结构文件，一个MYD表数据文件，一个.MYI索引文件。从MySQL5.0开始默认限制是256TB。</p>\\n<figure><img src=\\"https://fynotefile.oss-cn-zhangjiakou.aliyuncs.com/fynote/fyfile/16657/1607287731925286912/789d8c3ad02743b69ce4123954791b03.png\\" alt=\\"image.png\\" tabindex=\\"0\\" loading=\\"lazy\\"><figcaption>image.png</figcaption></figure>\\n</li>\\n</ul>","autoDesc":true}');export{n as data};
